package com.wuzhenhua.yunpicturebackend.service.impl;

import cn.hutool.core.io.FileUtil;
import cn.hutool.core.util.StrUtil;
import com.wuzhenhua.yunpicturebackend.config.CosClientConfig;
import com.wuzhenhua.yunpicturebackend.exception.BusinessException;
import com.wuzhenhua.yunpicturebackend.exception.ErrorCode;
import com.wuzhenhua.yunpicturebackend.manager.CosManager;
import com.wuzhenhua.yunpicturebackend.service.AvatarUploadService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.web.multipart.MultipartFile;

import java.io.File;
import java.net.URL;
import java.util.Arrays;
import java.util.List;

@Service
@Slf4j
public class AvatarUploadServiceImpl implements AvatarUploadService {

    @Resource
    private CosManager cosManager;

    @Resource
    private CosClientConfig cosClientConfig;

    private static final long MAX_FILE_SIZE = 2 * 1024 * 1024;
    private static final List<String> ALLOWED_FORMATS = Arrays.asList("jpg", "jpeg", "png", "webp");

    @Override
    public String uploadAvatarFromFile(MultipartFile file, Long userId) {
        if (file == null || file.isEmpty()) {
            throw new BusinessException(ErrorCode.PARAMS_ERROR, "文件不能为空");
        }

        if (file.getSize() > MAX_FILE_SIZE) {
            throw new BusinessException(ErrorCode.PARAMS_ERROR, "头像大小不能超过2MB");
        }

        String originalFilename = file.getOriginalFilename();
        String extension = FileUtil.getSuffix(originalFilename);
        if (!ALLOWED_FORMATS.contains(extension.toLowerCase())) {
            throw new BusinessException(ErrorCode.PARAMS_ERROR, "头像格式仅支持jpg/png/webp");
        }

        String filename = String.format("avatar/%d_%d.%s", userId, System.currentTimeMillis(), extension);

        try {
            File tempFile = File.createTempFile("avatar_", "." + extension);
            file.transferTo(tempFile);
            cosManager.putPictureObject(filename, tempFile);
            FileUtil.del(tempFile);

            String webpKey = FileUtil.mainName(filename) + ".webp";
            return cosClientConfig.getHost() + "/" + webpKey;
        } catch (Exception e) {
            log.error("上传头像失败", e);
            throw new BusinessException(ErrorCode.SYSTEM_ERROR, "上传失败");
        }
    }

    @Override
    public String uploadAvatarFromUrl(String fileUrl, Long userId) {
        if (StrUtil.isBlank(fileUrl)) {
            throw new BusinessException(ErrorCode.PARAMS_ERROR, "文件地址不能为空");
        }

        if (!fileUrl.startsWith("http://") && !fileUrl.startsWith("https://")) {
            throw new BusinessException(ErrorCode.PARAMS_ERROR, "仅支持http或https协议的文件地址");
        }

        try {
            URL url = new URL(fileUrl);
            String path = url.getPath();
            String extension = FileUtil.getSuffix(path);

            if (StrUtil.isBlank(extension) || !ALLOWED_FORMATS.contains(extension.toLowerCase())) {
                throw new BusinessException(ErrorCode.PARAMS_ERROR, "头像格式仅支持jpg/png/webp");
            }

            File tempFile = File.createTempFile("avatar_url_", "." + extension);
            FileUtil.downloadFile(fileUrl, tempFile);

            if (tempFile.length() > MAX_FILE_SIZE) {
                FileUtil.del(tempFile);
                throw new BusinessException(ErrorCode.PARAMS_ERROR, "头像大小不能超过2MB");
            }

            String filename = String.format("avatar/%d_%d.%s", userId, System.currentTimeMillis(), extension);
            cosManager.putPictureObject(filename, tempFile);
            FileUtil.del(tempFile);

            String webpKey = FileUtil.mainName(filename) + ".webp";
            return cosClientConfig.getHost() + "/" + webpKey;
        } catch (BusinessException e) {
            throw e;
        } catch (Exception e) {
            log.error("从URL上传头像失败: {}", fileUrl, e);
            throw new BusinessException(ErrorCode.SYSTEM_ERROR, "上传失败");
        }
    }

    @Override
    public void deleteOldAvatar(String avatarUrl) {
        if (StrUtil.isBlank(avatarUrl)) {
            return;
        }

        try {
            String host = cosClientConfig.getHost();
            if (avatarUrl.startsWith(host)) {
                String key = avatarUrl.substring(host.length() + 1);
                cosManager.deleteObject(key);
                log.info("删除旧头像成功: {}", key);
            }
        } catch (Exception e) {
            log.error("删除旧头像失败，但不阻塞主流程: {}", avatarUrl, e);
        }
    }
}

