package com.wuzhenhua.yunpicturebackend.service.impl;

import cn.hutool.core.io.FileUtil;
import cn.hutool.core.util.ArrayUtil;
import cn.hutool.core.util.StrUtil;
import cn.hutool.http.HttpResponse;
import cn.hutool.http.HttpStatus;
import cn.hutool.http.HttpUtil;
import cn.hutool.http.Method;
import com.wuzhenhua.yunpicturebackend.config.CosClientConfig;
import com.wuzhenhua.yunpicturebackend.exception.BusinessException;
import com.wuzhenhua.yunpicturebackend.exception.ErrorCode;
import com.wuzhenhua.yunpicturebackend.manager.CosManager;
import com.wuzhenhua.yunpicturebackend.service.AvatarUploadService;
import com.wuzhenhua.yunpicturebackend.utils.ThrowUtils;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.web.multipart.MultipartFile;

import java.io.File;
import java.net.MalformedURLException;
import java.net.URL;
import java.util.Arrays;
import java.util.List;

@Service
@Slf4j
public class AvatarUploadServiceImpl implements AvatarUploadService {

    @Resource
    private CosManager cosManager;

    @Resource
    private CosClientConfig cosClientConfig;

    @Override
    public String uploadAvatarFromFile(MultipartFile file, Long userId) {
        // 1. 验证文件
        validAvatarFile(file);

        // 2. 生成COS key
        String originalFilename = file.getOriginalFilename();
        String suffix = FileUtil.getSuffix(originalFilename);
        long timestamp = System.currentTimeMillis();
        String key = String.format("avatar/%s_%s.%s", userId, timestamp, suffix);

        // 3. 创建临时文件并上传
        File tempFile = null;
        try {
            tempFile = File.createTempFile("avatar_", "." + suffix);
            file.transferTo(tempFile);

            // 使用putPictureObject自动进行WebP压缩
            cosManager.putPictureObject(key, tempFile);

            // 4. 构造返回URL (WebP格式)
            String webpKey = FileUtil.mainName(key) + ".webp";
            return String.format("https://%s/%s", cosClientConfig.getHost(), webpKey);

        } catch (Exception e) {
            log.error("头像上传失败: userId={}, error={}", userId, e.getMessage());
            throw new BusinessException(ErrorCode.SYSTEM_ERROR, "头像上传失败");
        } finally {
            if (tempFile != null && tempFile.exists()) {
                tempFile.delete();
            }
        }
    }

    @Override
    public String uploadAvatarFromUrl(String fileUrl, Long userId) {
        // 1. 验证URL
        validAvatarUrl(fileUrl);

        // 2. 下载文件到临时目录
        File tempFile = null;
        try {
            String suffix = FileUtil.getSuffix(fileUrl);
            if (StrUtil.isBlank(suffix)) {
                suffix = "jpg"; // 默认格式
            }
            tempFile = File.createTempFile("avatar_url_", "." + suffix);
            HttpUtil.downloadFile(fileUrl, tempFile);

            // 3. 生成COS key
            long timestamp = System.currentTimeMillis();
            String key = String.format("avatar/%s_%s.%s", userId, timestamp, suffix);

            // 4. 上传到COS (自动WebP压缩)
            cosManager.putPictureObject(key, tempFile);

            // 5. 构造返回URL
            String webpKey = FileUtil.mainName(key) + ".webp";
            return String.format("https://%s/%s", cosClientConfig.getHost(), webpKey);

        } catch (Exception e) {
            log.error("URL头像上传失败: userId={}, url={}, error={}", userId, fileUrl, e.getMessage());
            throw new BusinessException(ErrorCode.SYSTEM_ERROR, "头像上传失败");
        } finally {
            if (tempFile != null && tempFile.exists()) {
                tempFile.delete();
            }
        }
    }

    @Override
    public void deleteOldAvatar(String avatarUrl) {
        if (StrUtil.isBlank(avatarUrl)) {
            return;
        }

        // 从URL中提取COS key
        String key = extractCosKey(avatarUrl);
        if (StrUtil.isBlank(key)) {
            log.warn("无法从URL提取COS key: {}", avatarUrl);
            return;
        }

        try {
            cosManager.deleteObject(key);
            log.info("旧头像删除成功: {}", key);
        } catch (Exception e) {
            log.warn("旧头像删除失败: key={}, error={}", key, e.getMessage());
            // 不抛异常，不阻塞主流程
        }
    }

    /**
     * 验证头像文件
     */
    private void validAvatarFile(MultipartFile file) {
        ThrowUtils.throwIf(file == null || file.isEmpty(), ErrorCode.PARAMS_ERROR, "头像文件不能为空");

        // 验证文件大小 (2MB)
        long fileSize = file.getSize();
        final long MAX_FILE_SIZE = 2 * 1024 * 1024;
        ThrowUtils.throwIf(fileSize > MAX_FILE_SIZE, ErrorCode.PARAMS_ERROR, "头像大小不能超过2MB");

        // 验证文件格式
        String filename = file.getOriginalFilename();
        String suffix = FileUtil.getSuffix(filename);
        final String[] ALLOWED_FORMATS = {"jpg", "jpeg", "png", "webp"};
        ThrowUtils.throwIf(!ArrayUtil.contains(ALLOWED_FORMATS, suffix.toLowerCase()),
            ErrorCode.PARAMS_ERROR, "头像格式仅支持jpg/png/webp");
    }

    /**
     * 验证头像URL
     */
    private void validAvatarUrl(String fileUrl) {
        ThrowUtils.throwIf(StrUtil.isBlank(fileUrl), ErrorCode.PARAMS_ERROR, "文件地址为空");

        // 验证URL格式
        try {
            new URL(fileUrl);
        } catch (MalformedURLException e) {
            throw new BusinessException(ErrorCode.PARAMS_ERROR, "文件地址格式不正确");
        }

        // 验证协议
        ThrowUtils.throwIf(!fileUrl.startsWith("http://") && !fileUrl.startsWith("https://"),
            ErrorCode.PARAMS_ERROR, "仅支持http或https协议的文件地址");

        // 发送HEAD请求验证
        HttpResponse httpResponse = null;
        try {
            httpResponse = HttpUtil.createRequest(Method.HEAD, fileUrl).execute();
            if (httpResponse.getStatus() != HttpStatus.HTTP_OK) {
                return;
            }

            // 验证Content-Type
            String contentType = httpResponse.header("Content-Type");
            if (StrUtil.isNotBlank(contentType)) {
                final List<String> ALLOW_CONTENT_TYPES = Arrays.asList(
                    "image/jpeg", "image/jpg", "image/png", "image/webp");
                ThrowUtils.throwIf(!ALLOW_CONTENT_TYPES.contains(contentType.toLowerCase()),
                    ErrorCode.PARAMS_ERROR, "文件类型错误");
            }

            // 验证Content-Length
            String contentLength = httpResponse.header("Content-Length");
            if (StrUtil.isNotBlank(contentLength)) {
                try {
                    long fileSize = Long.parseLong(contentLength);
                    final long MAX_FILE_SIZE = 2 * 1024 * 1024;
                    ThrowUtils.throwIf(fileSize > MAX_FILE_SIZE,
                        ErrorCode.PARAMS_ERROR, "头像大小不能超过2MB");
                } catch (NumberFormatException e) {
                    throw new BusinessException(ErrorCode.PARAMS_ERROR, "文件大小格式异常");
                }
            }
        } finally {
            if (httpResponse != null) {
                httpResponse.close();
            }
        }
    }

    /**
     * 从URL提取COS key
     */
    private String extractCosKey(String avatarUrl) {
        if (StrUtil.isBlank(avatarUrl)) {
            return null;
        }

        String host = cosClientConfig.getHost();
        if (!avatarUrl.contains(host)) {
            return null;
        }

        // 提取key: https://host/key -> key
        int hostIndex = avatarUrl.indexOf(host);
        String key = avatarUrl.substring(hostIndex + host.length() + 1);
        return key;
    }
}

